```
using UnityEngine;

public class CharacterController : MonoBehaviour
{
    public float speed = 10.0f; // movement speed of the character
    public float jumpForce = 10.0f; // force applied when jumping
    public float attackForce = 5.0f; // force applied when attacking

    private Rigidbody2D rb; // reference to the character's rigidbody
    private Animator anim; // reference to the character's animator

    void Start()
    {
        // get the character's rigidbody and animator components
        rb = GetComponent<Rigidbody2D>();
        anim = GetComponent<Animator>();
    }

    void Update()
    {
        // get the horizontal axis input (left/right movement)
        float moveX = Input.GetAxis("Horizontal");

        // move the character horizontally
        rb.velocity = new Vector2(moveX * speed, rb.velocity.y);

        // set the character's running animation
        anim.SetFloat("Speed", Mathf.Abs(moveX));

        // check for jump input
        if (Input.GetButtonDown("Jump"))
        {
            // apply a force upward to make the character jump
            rb.AddForce(new Vector2(0, jumpForce), ForceMode2D.Impulse);
        }

        // check for attack input
        if (Input.GetButtonDown("Attack"))
        {
            // apply a force forward when attacking
            rb.AddForce(new Vector2(attackForce, 0), ForceMode2D.Impulse);

            // play the attack animation
            anim.SetTrigger("Attack");
        }
    }
}
```
This is a simplified example of a character controller. In a real-world game, the character controller would likely be more complex, as it would need to handle collision detection, movement states like idling, running, and jumping, and various other types of inputs. The example I provided only handles the horizontal movement, jumping, and simple attacking logic. You would need to add additional logic to handle collision detection and other advanced features like dashing, sliding, crawling, etc.

It's also important to note that this is a starting point and further adjustment, optimization and debugging may be required as the development progress.

