import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

const App = () => {
  const [pokemonData, setPokemonData] = useState([]);
  const [pokemonTypes, setPokemonTypes] = useState([]);
  const [selectedType, setSelectedType] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalCount, setTotalCount] = useState(0);
  const pokemonPerPage = 20;

  useEffect(() => {
    const fetchTotalCount = async () => {
      const response = await axios.get('https://pokeapi.co/api/v2/pokemon');
      setTotalCount(response.data.count);
    };

    const fetchPokemonTypes = async () => {
      const response = await axios.get('https://pokeapi.co/api/v2/type');
      setPokemonTypes(response.data.results);
    };

    fetchTotalCount();
    fetchPokemonTypes();
  }, []);

  useEffect(() => {
    const fetchPokemonData = async () => {
      const allPokemon = [];

      for (
        let i = (currentPage - 1) * pokemonPerPage + 1;
        i <= currentPage * pokemonPerPage && i <= totalCount;
        i++
      ) {
        const response = await axios.get(`https://pokeapi.co/api/v2/pokemon/${i}`);
        allPokemon.push(response.data);
      }

      setPokemonData(allPokemon);
    };

    fetchPokemonData();
  }, [currentPage, totalCount]);

  const filterByType = (type) => {
    setSelectedType(type);
    setCurrentPage(1);
  };

  const totalPages = Math.ceil(totalCount / pokemonPerPage);

  const filteredPokemon = selectedType
    ? pokemonData.filter((pokemon) =>
        pokemon.types.some((typeInfo) => typeInfo.type.name === selectedType)
      )
    : pokemonData;

  return (
    <div className="App">
      <h1>Pokédex</h1>
      <div className="type-filter">
        {pokemonTypes.map((type) => (
          <button key={type.name} onClick={() => filterByType(type.name)}>
            {type.name}
          </button>
        ))}
        <button onClick={() => filterByType(null)}>Clear filter</button>
      </div>
      <div className="pagination">
        <button onClick={() => setCurrentPage(Math.max(currentPage - 1, 1))}>&lt; Prev</button>
        <span>
          Page {currentPage} of {totalPages}
        </span>
        <button onClick={() => setCurrentPage(Math.min(currentPage + 1, totalPages))}>Next &gt;</button>
      </div>
      {filteredPokemon.map((pokemon) => (
        <div key={pokemon.id} className="pokemon">
          <h2>{pokemon.name}</h2>
          <img src={pokemon.sprites.front_default} alt={pokemon.name} />
          <p>Height: {pokemon.height}</p>
          <p>Weight: {pokemon.weight}</p>
          <p>Types: {pokemon.types.map((type) => type.type.name).join(', ')}</p>
          <p>Abilities: {pokemon.abilities.map((ability) => ability.ability.name).join(', ')}</p>
        </div>
      ))}
    </div>
  );
};

export default App;
